-- Create "production_order_material_requirements" table
CREATE TABLE "production_order_material_requirements" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "unit_quantity_snapshot" numeric(20,6) NOT NULL,
  "loss_rate_snapshot" numeric(20,6) NOT NULL,
  "planned_quantity" numeric(20,6) NOT NULL,
  "material_code_snapshot" character varying NOT NULL,
  "material_name_snapshot" character varying NOT NULL,
  "unit_code_snapshot" character varying NOT NULL,
  "unit_name_snapshot" character varying NOT NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "bom_header_id" bigint NOT NULL,
  "bom_item_id" bigint NOT NULL,
  "material_id" bigint NOT NULL,
  "production_order_id" bigint NOT NULL,
  "production_order_item_id" bigint NOT NULL,
  "unit_id" bigint NOT NULL,
  PRIMARY KEY ("id"),
  CONSTRAINT "production_order_material_requirements_bom_headers_production_o" FOREIGN KEY ("bom_header_id") REFERENCES "bom_headers" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_material_requirements_bom_items_production_ord" FOREIGN KEY ("bom_item_id") REFERENCES "bom_items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_material_requirements_materials_production_ord" FOREIGN KEY ("material_id") REFERENCES "materials" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_material_requirements_production_order_items_m" FOREIGN KEY ("production_order_item_id") REFERENCES "production_order_items" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_material_requirements_production_orders_materi" FOREIGN KEY ("production_order_id") REFERENCES "production_orders" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_material_requirements_units_production_order_m" FOREIGN KEY ("unit_id") REFERENCES "units" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION,
  CONSTRAINT "production_order_material_requirements_loss_rate_non_negative" CHECK (loss_rate_snapshot >= (0)::numeric),
  CONSTRAINT "production_order_material_requirements_planned_quantity_positiv" CHECK (planned_quantity > (0)::numeric),
  CONSTRAINT "production_order_material_requirements_unit_quantity_positive" CHECK (unit_quantity_snapshot > (0)::numeric)
);
-- Create index "productionordermaterialrequirement_material_id_unit_id" to table: "production_order_material_requirements"
CREATE INDEX "productionordermaterialrequirement_material_id_unit_id" ON "production_order_material_requirements" ("material_id", "unit_id");
-- Create index "productionordermaterialrequirement_production_order_id_producti" to table: "production_order_material_requirements"
CREATE INDEX "productionordermaterialrequirement_production_order_id_producti" ON "production_order_material_requirements" ("production_order_id", "production_order_item_id");
-- Create index "productionordermaterialrequirement_production_order_item_id_bom" to table: "production_order_material_requirements"
CREATE UNIQUE INDEX "productionordermaterialrequirement_production_order_item_id_bom" ON "production_order_material_requirements" ("production_order_item_id", "bom_item_id");
